CREATE INDEX IF NOT EXISTS idx_bookings_created_at ON bookings(createdAt);

-- Notes: queried by bookingId constantly
CREATE INDEX IF NOT EXISTS idx_notes_booking_id ON notes(bookingId);
CREATE INDEX IF NOT EXISTS idx_notes_author_id ON notes(authorId);
CREATE INDEX IF NOT EXISTS idx_notes_created_at ON notes(createdAt);

-- In-app notifications: queried by userId and read status
CREATE INDEX IF NOT EXISTS idx_in_app_notif_user_id ON in_app_notifications(userId);
