CREATE INDEX IF NOT EXISTS idx_refunds_agent_id ON refunds(agentId);

-- Message threads
CREATE INDEX IF NOT EXISTS idx_booking_messages_booking_id ON booking_messages(bookingId);
CREATE INDEX IF NOT EXISTS idx_booking_messages_created_at ON booking_messages(createdAt);

-- Recruitment prospects
CREATE INDEX IF NOT EXISTS idx_recruitment_prospects_email ON recruitment_prospects(email);
